function add(a,b){return a+b;}function sub(a,b){return a-b;}function mul(a,b){return a*b;}function div(a,b){return a/b;}function main(){var x=add(1,2);var y=sub(10,3);var z=mul(4,5);var w=div(20,4);var total=x+y+z+w;var msg="result is "+total;console.log(msg);return total;}function helper(n){return n*n;}function more(n){return helper(n)+1;}var r=main();var s=more(r);console.log(s);function final(value){var inner=value*2;var outer=inner+10;return outer;}var f=final(s);console.log("final value",f);
